```c
#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    if (k > 70) {
        printf("No\n");
        return 0;
    }

    int s[71] = {0};
    int count = 0;
    for (int i = 1; i <= k; i++) {
        int mod = n % i;
        int found = 0;
        for (int j = 0; j < count; j++) {
            if (s[j] == mod) {
                found = 1;
                break;
            }
        }
        if (!found) {
            s[count++] = mod;
        }
    }

    printf(count == k ? "Yes\n" : "No\n");
    return 0;
}
